import * as socketIo from 'socket.io-client';
/**
 * @ignore
 */
export class PromobotLoggerConnection {
    constructor(options = {}) {
        this.messages = [];
        this.options = options;
        this.active = false;
        const socketOptions = Object.assign({
            secure: false,
            reconnection: true,
            reconnectionDelay: 5000,
            reconnectionDelayMax: 50000,
            reconnectionAttempts: Infinity,
        }, options);
        this.socket = socketIo.connect(this.options.url, {
            secure: socketOptions.secure,
            reconnection: socketOptions.reconnection,
            reconnectionDelay: socketOptions.reconnectionDelay,
            reconnectionDelayMax: socketOptions.reconnectionDelayMax,
            reconnectionAttempts: socketOptions.reconnectionAttempts,
        });
        this.socket.on('connect', () => {
            this.active = true;
            this.sendMessages();
        });
        this.socket.on('disconnect', () => {
            this.active = false;
        });
        this.socket.on('reconnect', (attempt) => {
            // console.log('reconnect', attempt)
            this.active = true;
            this.sendMessages();
        });
        this.socket.on('error', () => {
            // console.log('error')
        });
        this.socket.on('connect_failed', () => {
            // console.log('connect_failed')
        });
        this.socket.on('reconnect_attempt', (attempt) => {
            // console.log('reconnect_attempt', attempt)
        });
        this.socket.on('reconnect_error', (e) => {
            // console.log('reconnect_error', e)
            this.active = false;
        });
    }
    send(message) {
        this.messages.push(message);
        this.sendMessages();
    }
    sendMessages() {
        if (this.active) {
            while (this.socket.connected && this.messages.length !== 0) {
                const message = this.messages.shift();
                if (this.options.room) {
                    this.socket.emit('event', this.options.room, message);
                }
                else {
                    this.socket.emit('event', message);
                }
            }
        }
    }
}
